use std::{env, fs, path::PathBuf};

use context_relay_protocol::{PROTOCOL_VERSION, ProtocolInfo};
use ts_rs::TS;

fn main() {
    let output = env::args_os()
        .nth(1)
        .map(PathBuf::from)
        .unwrap_or_else(|| PathBuf::from("apps/desktop/src/bindings.ts"));
    let bindings = format!(
        "// Generated by context-relay-protocol. Do not edit.\n\nexport const PROTOCOL_VERSION = {PROTOCOL_VERSION} as const;\n\nexport {}\n",
        ProtocolInfo::decl()
    );

    fs::write(output, bindings).expect("TypeScript bindings should be writable");
}
